<template>
  <div class="min-h-screen bg-slate-50 flex items-center justify-center p-6">
    <div class="w-full max-w-2xl">
      <div class="bg-white rounded-xl shadow p-6">
        <h1 class="text-2xl font-bold mb-4">Manage your transaction</h1>
        <p class="text-sm text-slate-600 mb-4">Enter your Transaction ID and the email used to pay. No account required.</p>

        <form @submit.prevent="accessTransaction" class="space-y-4">
          <div>
            <label class="block text-sm font-medium text-slate-700">Transaction ID</label>
            <input v-model="form.transactionId" type="text" required class="w-full mt-1 px-3 py-2 border rounded-lg" />
          </div>

          <div>
            <label class="block text-sm font-medium text-slate-700">Email used for the payment</label>
            <input v-model="form.email" type="email" required class="w-full mt-1 px-3 py-2 border rounded-lg" />
          </div>

          <div class="flex gap-3">
            <button type="submit" :disabled="isLoading" class="btn-primary">Access transaction</button>
            <button type="button" @click="reset" class="btn-secondary">Reset</button>
          </div>
        </form>

        <div v-if="error" class="mt-4 text-red-600">{{ error }}</div>

        <div v-if="transaction" class="mt-6">
          <h2 class="text-lg font-semibold">Transaction</h2>
          <div class="mt-2 grid grid-cols-1 sm:grid-cols-3 gap-3">
            <div class="rounded p-3 bg-slate-50">
              <p class="text-xs text-slate-500">Transaction ID</p>
              <p class="font-mono">{{ transaction.id }}</p>
            </div>
            <div class="rounded p-3 bg-slate-50">
              <p class="text-xs text-slate-500">Amount</p>
              <p class="font-semibold">{{ transaction.currency }} {{ transaction.amount.toFixed(2) }}</p>
            </div>
            <div class="rounded p-3 bg-slate-50">
              <p class="text-xs text-slate-500">Status</p>
              <p class="font-semibold">{{ transaction.status }}</p>
            </div>
          </div>

          <div class="mt-4">
            <p class="text-sm text-slate-600">You can submit a refund request for this transaction (if eligible).</p>
            <div class="mt-3">
              <button v-if="showAccessed" @click="openRefund" class="btn-primary">Request refund</button>
            </div>
          </div>

          <RefundDialog
            v-model="showRefundDialog"
            :currency="transaction.currency"
            :transaction-amount="transaction.amount"
            :processing="isSubmitting"
            :server-error="refundError"
            eyebrow="Customer refund request"
            title="Request a refund"
            description="Tell us why you'd like to request a refund for this transaction."
            @confirm="submitRefund"
          />
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { reactive, ref } from 'vue'
import { watch, onMounted } from 'vue'
import { useRoute } from 'vue-router'
import RefundDialog from '@/components/shared/RefundDialog.vue'
import { authService } from '@/services/auth'
import { refundService } from '@/services/refunds'
import { transactionService } from '@/services/transactions'
import { useNotificationStore } from '@/stores/notifications'
import type { Transaction } from '@/types'

const notificationStore = useNotificationStore()
const route = useRoute()
onMounted(() => {
  // Pre-fill from query params if provided
  const { transactionId, email } = route.query
  if (transactionId && email) {
    const txId = Array.isArray(transactionId) ? transactionId[0] : transactionId
    const emailVal = Array.isArray(email) ? email[0] : email
    if (txId && emailVal) {
      form.transactionId = txId
      form.email = emailVal
    }
    // Auto-submit if both params are present
    if (txId && emailVal) {
      accessTransaction()
    }
  }
})


const form = reactive({ transactionId: '', email: '' })
const isLoading = ref(false)
const error = ref<string | null>(null)

const transaction = ref<Transaction | null>(null)
const customerToken = ref<string | null>(null)
const showAccessed = ref(false)

const showRefundDialog = ref(false)
const isSubmitting = ref(false)
const refundError = ref<string | null>(null)

async function accessTransaction() {
  error.value = null
  transaction.value = null
  showAccessed.value = false

  if (!form.transactionId || !form.email) {
    error.value = 'Both Transaction ID and Email are required.'
    return
  }

  isLoading.value = true
  try {
    // Issue a temporary customer token for this transaction
    const resp = await authService.issueCustomerToken(form.transactionId, form.email)
    customerToken.value = resp.token

    // Fetch transaction details using the temp token
    transaction.value = await transactionService.getByIdWithToken(form.transactionId, customerToken.value)
    showAccessed.value = true
    notificationStore.success('Access granted for transaction')
  } catch (err: any) {
    error.value = err.response?.data?.message || 'Failed to access transaction. Check your Transaction ID and email.'
  } finally {
    isLoading.value = false
  }
}

function reset() {
  form.transactionId = ''
  form.email = ''
  transaction.value = null
  customerToken.value = null
  showAccessed.value = false
  error.value = null
}

function openRefund() {
  showRefundDialog.value = true
}

async function submitRefund(payload: { amount: number; reason: string }) {
  if (!transaction.value || !customerToken.value) return
  isSubmitting.value = true
  refundError.value = null
  try {
    const created = await refundService.requestByCustomerWithToken({
      transactionId: transaction.value.id,
      amount: payload.amount,
      reason: payload.reason,
    }, customerToken.value)
    notificationStore.success('Refund request submitted')
    showRefundDialog.value = false
  } catch (err: any) {
    refundError.value = err.response?.data?.message || 'Failed to submit refund request'
    notificationStore.error(refundError.value || 'Failed to submit refund request')
  } finally {
    isSubmitting.value = false
  }
}
</script>





